import React from "react";
import { NavLink } from "react-router-dom";

const Navbar: React.FC = () => {
  const linkClasses = ({ isActive }: { isActive: boolean }) =>
    `text-sm font-semibold transition ${isActive ? "text-blue-700" : "text-slate-600 hover:text-blue-600"}`;

  return (
    <header className="sticky top-0 z-30 border-b border-slate-200 bg-white/90 backdrop-blur">
      <nav className="mx-auto flex max-w-6xl items-center justify-between px-4 py-4 sm:px-6 lg:px-8">
        <NavLink to="/" className="text-xl font-bold text-slate-900">
          Bus Booking
        </NavLink>
        <div className="flex items-center gap-6">
          <NavLink to="/" className={linkClasses} end>
            Home
          </NavLink>
          <NavLink to="/buses" className={linkClasses}>
            Buses
          </NavLink>
          <NavLink to="/my-bookings" className={linkClasses}>
            My Bookings
          </NavLink>
        </div>
      </nav>
    </header>
  );
};

export default Navbar;
